INSERT OR REPLACE INTO quality_profiles (name, description, upgrades_allowed, minimum_custom_format_score, upgrade_until_score, upgrade_score_increment) VALUES ('1080p Quality', '1080p Quality utilizes the **Golden Popcorn Performance Index** to target **Transparent** x264 1080p Encodes. 

- Average Movie Sizes ~ 10 to 15gb per Movie
